import json, os, glob
latest=sorted(glob.glob("/home/bot/.pig/agent/sessions/--home-bot--/*.jsonl"), key=os.path.getmtime, reverse=True)[0]
print("latest", latest)
for i,line in enumerate(open(latest),1):
    obj=json.loads(line)
    if obj.get("type")=="message":
        msg=obj.get("message",{})
        role=msg.get("role")
        texts=[]
        for c in msg.get("content",[]) or []:
            if c.get("type")=="text": texts.append(c.get("text","")[:160])
            elif c.get("type")=="toolCall": texts.append("TOOLCALL:"+c.get("name",""))
        print(i, role, " | ".join(texts), msg.get("errorMessage", ""))
    else:
        print(i, obj.get("type"), obj.get("timestamp", ""))
